import{_ as n,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Anhang: Technische Referenz | Antigravity Auth","description":"Erfahren Sie mehr über die technische Referenz des Antigravity Auth Plugins, einschließlich Architekturdesign, API-Spezifikation, Speicherformat und vollständiger Konfigurationsoptionen, um die internen Mechanismen des Plugins tiefgreifend zu verstehen.","frontmatter":{"title":"Anhang: Technische Referenz | Antigravity Auth","sidebarTitle":"Plugin-Architektur verstehen","subtitle":"Anhang: Architektur, API und Konfigurationsreferenz","description":"Erfahren Sie mehr über die technische Referenz des Antigravity Auth Plugins, einschließlich Architekturdesign, API-Spezifikation, Speicherformat und vollständiger Konfigurationsoptionen, um die internen Mechanismen des Plugins tiefgreifend zu verstehen.","order":5},"headers":[],"relativePath":"de/NoeFabris/opencode-antigravity-auth/appendix/index.md","filePath":"de/NoeFabris/opencode-antigravity-auth/appendix/index.md"}'),r={name:"de/NoeFabris/opencode-antigravity-auth/appendix/index.md"};function o(s,e,l,h,u,d){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="anhang" tabindex="-1">Anhang <a class="header-anchor" href="#anhang" aria-label="Permalink to &quot;Anhang&quot;">​</a></h1><p>Dieses Kapitel bietet technische Referenzmaterialien für das Antigravity Auth Plugin, einschließlich Architekturdesign, API-Spezifikation, Speicherformat und vollständigem Konfigurationshandbuch, um Ihnen ein tiefgreifendes Verständnis der internen Mechanismen des Plugins zu ermöglichen.</p><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><h3 id="_1-architekturubersicht" tabindex="-1">1. <a href="./architecture-overview/">Architekturübersicht</a> <a class="header-anchor" href="#_1-architekturubersicht" aria-label="Permalink to &quot;1. [Architekturübersicht](./architecture-overview/)&quot;">​</a></h3><p>Verstehen Sie die Modulstruktur und den Anfrageverarbeitungsablauf des Plugins.</p><ul><li>Modulare Schichtarchitektur und Verantwortlichkeiten</li><li>Vollständiger Anfragepfad von OpenCode zur Antigravity API</li><li>Multi-Account-Load-Balancing und Sitzungswiederherstellungsmechanismus</li></ul><h3 id="_2-api-spezifikation" tabindex="-1">2. <a href="./api-spec/">API-Spezifikation</a> <a class="header-anchor" href="#_2-api-spezifikation" aria-label="Permalink to &quot;2. [API-Spezifikation](./api-spec/)&quot;">​</a></h3><p>Vertiefen Sie Ihr Wissen über die technischen Details der Antigravity API.</p><ul><li>Einheitliche Gateway-Schnittstelle und Endpunktkonfiguration</li><li>Anfrage-/Antwortformat und JSON-Schema-Einschränkungen</li><li>Thinking-Modellkonfiguration und Funktionsaufrufregeln</li></ul><h3 id="_3-speicherformat" tabindex="-1">3. <a href="./storage-schema/">Speicherformat</a> <a class="header-anchor" href="#_3-speicherformat" aria-label="Permalink to &quot;3. [Speicherformat](./storage-schema/)&quot;">​</a></h3><p>Verstehen Sie die Struktur der Account-Speicherdatei und die Versionsverwaltung.</p><ul><li>Speicherort der Datei und Bedeutung der einzelnen Felder</li><li>v1/v2/v3-Versionsentwicklung und automatische Migration</li><li>Methoden zur Migration der Account-Konfiguration zwischen Rechnern</li></ul><h3 id="_4-vollstandige-konfigurationsoptionen" tabindex="-1">4. <a href="./all-config-options/">Vollständige Konfigurationsoptionen</a> <a class="header-anchor" href="#_4-vollstandige-konfigurationsoptionen" aria-label="Permalink to &quot;4. [Vollständige Konfigurationsoptionen](./all-config-options/)&quot;">​</a></h3><p>Vollständiges Referenzhandbuch für alle Konfigurationsoptionen.</p><ul><li>Standardwerte und Anwendungsszenarien für über 30 Konfigurationsoptionen</li><li>Methoden zur Überschreibung der Konfiguration durch Umgebungsvariablen</li><li>Optimale Konfigurationskombinationen für verschiedene Anwendungsszenarien</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Empfohlen: Zuerst abschließen</p><p>Der Inhalt dieses Kapitels ist technisch anspruchsvoll. Es wird empfohlen, zunächst folgende Abschnitte zu absolvieren:</p><ul><li><a href="./../start/quick-install/">Schnellinstallation</a> - Plugin-Installation und erste Authentifizierung abschließen</li><li><a href="./../advanced/configuration-guide/">Konfigurationsleitfaden</a> - Gängige Konfigurationsmethoden kennenlernen</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss des Anhangs können Sie:</p><ul><li>Die <a href="./../faq/">Häufig gestellten Fragen</a> konsultieren, um Probleme bei der Nutzung zu lösen</li><li>Das <a href="./../changelog/version-history/">Änderungsprotokoll</a> verfolgen, um über Versionsänderungen informiert zu bleiben</li><li>An der Plugin-Entwicklung teilnehmen und Code oder Dokumentation beitragen</li></ul>',20)])])}const f=n(r,[["render",o]]);export{g as __pageData,f as default};
